#!/usr/bin/env python3

import os
from pathlib import Path

import click
import yaml
from cryptography.hazmat.primitives.serialization import (
    Encoding,
    NoEncryption,
    PrivateFormat,
    PublicFormat,
    load_pem_private_key,
)

HERE = Path(__file__).parent
ROOT = HERE.parent.parent.resolve()

COMMENT = f"""# This file is auto-generated by `{Path(__file__).resolve().relative_to(ROOT)}`.
# Do not edit this file directly. Instead, run `make gen` or `make certs`
# in the root directory.
"""
CONFIG_DIR = ROOT / "tests" / "tropic_model"
DEST_PATH = CONFIG_DIR / "config.yml"
BASE_CONFIG = CONFIG_DIR / "base_config.yml"
CERT_CHAIN_DIR = CONFIG_DIR / "tropic_cert_chain"
CERT_STORE_PATH = CERT_CHAIN_DIR / "cert_store.der"


@click.command()
@click.option("--check", is_flag=True)
def generate_config(check: bool) -> None:
    device_private_key = load_pem_private_key(
        (CERT_CHAIN_DIR / "l3.key").read_bytes(), None
    )
    cert_store = CERT_STORE_PATH.read_bytes()

    config_dict = {
        "s_t_priv": device_private_key.private_bytes(
            Encoding.Raw, PrivateFormat.Raw, NoEncryption()
        ),
        "s_t_pub": device_private_key.public_key().public_bytes(
            Encoding.Raw, PublicFormat.Raw
        ),
        "x509_certificate": cert_store,
        "debug_random_value": b"\x00\xc0\xff\xee",
        "riscv_fw_version": "1.0.0",  # Version of the RISCV Firmware (also know as Application FW) used in TS7 devices
        "spect_fw_version": "1.0.0",
    }

    base_config = yaml.safe_load(BASE_CONFIG.read_text())
    overlap = config_dict.keys() & base_config.keys()
    if overlap:
        raise click.ClickException(
            f"Key collision between base_config and generated config: {overlap}"
        )
    config = COMMENT + yaml.dump({**base_config, **config_dict})

    if check:
        if not DEST_PATH.exists():
            print(f"{DEST_PATH} missing")
            raise click.ClickException("Config file is missing")
        elif config != DEST_PATH.read_text():
            print(f"{DEST_PATH} is out of date")
            raise click.ClickException("Config file is out of date")
        if not CERT_STORE_PATH.exists():
            print(f"{CERT_STORE_PATH} missing")
            raise click.ClickException("Cert store file is missing")
    else:
        DEST_PATH.write_text(config)
        base_config_stat = BASE_CONFIG.stat()
        os.utime(
            DEST_PATH,
            ns=(base_config_stat.st_atime_ns, base_config_stat.st_mtime_ns),
        )


if __name__ == "__main__":
    generate_config()
